import { NextResponse } from "next/server";
import { auth } from "@/auth";
import { prisma } from "@/lib/db";

export async function GET(
    req: Request,
    { params }: { params: { id: string } }
) {
    const session = await auth();
    if (!session) {
        return NextResponse.json({ error: "Não autorizado" }, { status: 401 });
    }

    try {
        const channels: any[] = await prisma.$queryRawUnsafe(
            `SELECT * FROM "WhatsAppChannel" WHERE "id" = ? LIMIT 1`,
            params.id
        );

        const channel = channels[0];

        if (!channel) {
            return NextResponse.json({ error: "Canal não encontrado" }, { status: 404 });
        }

        // Mock de QR Code
        const mockQrCode = "data:image/png;base64,";

        return NextResponse.json({ qrcode: mockQrCode });
    } catch (error) {
        console.error("[WHATSAPP_CHANNEL_QRCODE]", error);
        return NextResponse.json({ error: "Erro ao gerar QR Code" }, { status: 500 });
    }
}
